module register_8bit_enable(rst, enable, d, q);  

    input  rst;  
    input  enable;  
    input  [7:0] d;  
    output  [7:0] q;  
    reg   [7:0]  q; 
    initial q = 0;

    always @(posedge rst)
          begin
            if (enable)
                q <= d;
          end  

endmodule
